from django.shortcuts import renderfrom .motor_calculo import *def moeda_para_float(valor):    if not valor:        return 0    valor = valor.replace("R$", "")    valor = valor.replace(".", "")    valor = valor.replace(",", ".")    valor = valor.strip()    return float(valor)def calculo(request):    resultado = None    if request.method == "POST":        valor = moeda_para_float(request.POST.get("valor_base"))        tipo = request.POST.get("tipo_ato")        aliquota = float(request.POST.get("aliquota"))        if tipo == "venda_compra":            resultado = venda_compra(valor, aliquota)        elif tipo == "venda_cessao":            valor_cessao = moeda_para_float(                request.POST.get("valor_cessao")            )            resultado = venda_cessao(                valor,                valor_cessao,                aliquota            )        elif tipo == "alienacao":            divida = moeda_para_float(                request.POST.get("valor_divida")            )            resultado = alienacao_fiduciaria(                valor,                divida,                aliquota            )        elif tipo == "venda_usufruto":            resultado = venda_usufruto(                valor,                aliquota            )        elif tipo == "doacao":            resultado = doacao_inventario(valor)        elif tipo == "doacao_usufruto":            resultado = doacao_usufruto(valor)        elif tipo == "venda_desconto":            resultado = venda_desconto(                valor,                aliquota            )    return render(        request,        "calculo.html",        {"resultado": resultado}    )